-- SEED: GUIDED MEDITATIONS (one per day of week)
-- ============================================================
INSERT INTO guided_meditations (title, subtitle, day_of_week, duration_minutes, content, theme) VALUES
('Respiração Consciente', 'Começando a semana com presença', 0, 8,
E'Encontre uma posição confortável. Feche os olhos.\n\nInspire pelo nariz contando até 4... segure por 4... expire pela boca contando até 6.\n\nRepita esse ciclo por 5 minutos. A cada expiração, imagine que você está soltando tudo que não precisa mais carregar.\n\nSe pensamentos vierem, tudo bem. Apenas observe-os como nuvens passando, e volte sua atenção para a respiração.\n\nAo final, abra os olhos devagar. Você começou essa semana presente.',
'respiração'),
('Varredura Corporal', 'Encontrando tensões e as liberando', 1, 12,
E'Deite-se ou sente-se confortavelmente. Feche os olhos.\n\nComece prestando atenção nos seus pés. Como eles estão? Pesados? Cansados? Apenas observe.\n\nSuba lentamente a atenção pelas panturrilhas, joelhos, coxas... observe sem julgamento.\n\nContinue pela região do quadril, barriga, peito... Onde há tensão? Respire para esses lugares.\n\nSiga pelos ombros, braços, mãos... pelo pescoço, mandíbula, testa...\n\nAo chegar ao topo da cabeça, faça uma respiração profunda e solte tudo.',
'corpo'),
('Âncora no Presente', 'Para momentos de ansiedade', 2, 10,
E'Quando a ansiedade bater, esta meditação é uma âncora.\n\n5 coisas que você vê ao redor. Nomeie cada uma mentalmente.\n4 coisas que você pode tocar. Sinta a textura, a temperatura.\n3 coisas que você pode ouvir. Sons próximos, sons distantes.\n2 coisas que você pode cheirar. Seja o que for.\n1 coisa que você pode saborear.\n\nAgora respire fundo. Você está aqui. Você está presente. Esse momento é real e seguro.',
'ansiedade'),
('Corpo que Sente', 'Para dias de dor física', 3, 15,
E'Esta meditação é especialmente para quem vive com dor física.\n\nFeche os olhos e respire. Vá até o lugar da dor com curiosidade, não com resistência.\n\nComo é essa dor? Ela tem cor? Formato? Temperatura?\n\nAo invés de lutar contra ela, tente apenas observá-la. Às vezes a resistência à dor dói mais do que a própria dor.\n\nRespire para esse lugar. Diga a si mesmo: "Eu vejo você. Você não define quem sou, mas faço parte de mim agora."\n\nVocê não está sozinho na sua dor.',
'dor'),
('Gratidão Profunda', 'Cultivando o que há de bom', 4, 10,
E'Respire fundo. Hoje vamos cultivar gratidão — não como obrigação, mas como reconhecimento.\n\nPense em uma coisa pequena de hoje que foi boa. Pode ser o sabor do café, uma mensagem de um amigo, um raio de sol.\n\nFique com essa lembrança por um momento. Deixe ela se expandir no peito.\n\nAgora pense em uma pessoa que você é grato por ter em sua vida. Não precisa ser perfeita — apenas alguém que importa.\n\nPor fim, volte para si mesmo. O que em você merece reconhecimento hoje? Um esforço, uma escolha, um momento de coragem?\n\nGratidão começa quando aprendemos a ver.',
'gratidão'),
('Escrita Interior', 'Colocando em palavras o que sente', 5, 8,
E'Esta é uma meditação de escrita. Prepare papel e caneta, ou abra seu diário.\n\nFeche os olhos por 2 minutos. Apenas observe o que está sentindo agora. Sem analisar, sem julgar.\n\nAgora abra os olhos e escreva livremente por 5-10 minutos. Pode ser sobre qualquer coisa. Pode não fazer sentido.\n\nSe não souber por onde começar, use: "Agora eu me sinto..."\n\nEscrever é uma forma de dar forma ao que parece sem forma. Suas palavras importam.',
'escrita'),
('Descanso Merecido', 'Preparando para uma noite tranquila', 6, 12,
E'É fim de semana. Você chegou até aqui. Isso merece reconhecimento.\n\nDeite-se. Permita que seu corpo afunde na superfície abaixo de você.\n\nRespire lentamente. A cada expiração, deixe os pensamentos do dia irem embora.\n\nNão há nada que você precise fazer agora. Nenhum problema para resolver, nenhuma lista para cumprir.\n\nImagine um lugar onde você se sente completamente seguro. Pode ser real ou imaginado. Fique lá por alguns minutos.\n\nVocê merece descanso. Você merece paz.',
'descanso')
ON CONFLICT DO NOTHING;

-- ============================================================
-- SEED: MINI CHALLENGES
-- ============================================================
INSERT INTO mini_challenges (title, slug, description, duration_days, days) VALUES
(
  '7 Dias de Sono Melhor',
  '7-dias-sono-melhor',
  'Uma semana de práticas simples para melhorar a qualidade do seu sono e acordar mais descansado.',
  7,
  '[
    {"day":1,"title":"Horário fixo","description":"Defina um horário para dormir e acordar","activity":"Escolha hoje seu horário ideal e anote no diário","tip":"Consistência é mais importante do que quantidade de horas"},
    {"day":2,"title":"Desintoxicação digital","description":"Sem telas 1 hora antes de dormir","activity":"Substitua o celular por um livro ou meditação","tip":"A luz azul das telas atrapalha a produção de melatonina"},
    {"day":3,"title":"Ritual noturno","description":"Crie uma sequência de ações que sinalizem ao corpo que é hora de dormir","activity":"Escolha 3 atividades calmas para fazer antes de dormir","tip":"Chá de camomila, banho morno e leitura funcionam bem"},
    {"day":4,"title":"Quarto como santuário","description":"Ajuste seu ambiente para o sono","activity":"Escureça o quarto, ajuste a temperatura, reduza barulhos","tip":"O quarto deve ser associado apenas ao sono e descanso"},
    {"day":5,"title":"Movimento durante o dia","description":"Atividade física melhora o sono à noite","activity":"Faça pelo menos 20 minutos de movimento hoje","tip":"Evite exercícios intensos perto da hora de dormir"},
    {"day":6,"title":"Alimentação e sono","description":"O que você come afeta como você dorme","activity":"Evite cafeína após o almoço e refeições pesadas à noite","tip":"Um lanche leve com carboidrato pode ajudar a dormir"},
    {"day":7,"title":"Reflexão e continuidade","description":"Celebre uma semana de cuidado com o sono","activity":"Anote no diário o que funcionou e o que quer manter","tip":"Você construiu um alicerce. Continue!"}
  ]'::jsonb
),
(
  '5 Dias de Autocuidado com Dor Crônica',
  '5-dias-autocuidado-dor-cronica',
  'Cinco dias de práticas gentis para quem convive com dor crônica, respeitando os limites do corpo.',
  5,
  '[
    {"day":1,"title":"Ouvir o corpo","description":"Hoje o objetivo é apenas observar, sem julgamento","activity":"Faça um diário da dor: quando foi mais intensa, o que aliviou, como se sentiu emocionalmente","tip":"Conhecer os padrões da dor é o primeiro passo para manejá-la"},
    {"day":2,"title":"Movimento gentil","description":"O corpo em movimento suave libera substâncias que aliviam a dor","activity":"10 minutos de alongamento suave ou caminhada no ritmo que seu corpo pedir","tip":"Não force. Se doer, pare. O objetivo é gentileza"},
    {"day":3,"title":"Calor e frio terapêuticos","description":"Temperatura pode ser uma aliada no alívio da dor","activity":"Experimente bolsa de água quente ou compressa fria na área mais afetada","tip":"Calor relaxa músculos, frio reduz inflamação — veja o que funciona para você"},
    {"day":4,"title":"Conexão e apoio","description":"Isolamento amplifica a dor. Conexão alivia.","activity":"Fale com alguém de confiança sobre como está se sentindo","tip":"Você não precisa resolver sozinho. Deixar entrar também é cuidado"},
    {"day":5,"title":"Compaixão própria","description":"Conviver com dor crônica exige uma dose enorme de compaixão consigo mesmo","activity":"Escreva uma carta para você mesmo, reconhecendo o quanto carrega e o quanto é forte","tip":"Você está fazendo muito mais do que parece. Sua luta é real e merece reconhecimento"}
  ]'::jsonb
),
(
  '7 Dias de Respiração Consciente',
  '7-dias-respiracao-consciente',
  'Sete técnicas de respiração para reduzir ansiedade, regular o sistema nervoso e trazer mais presença.',
  7,
  '[
    {"day":1,"title":"Respiração Diafragmática","description":"A respiração mais fundamental — aprenda a respirar com o diafragma","activity":"Coloque uma mão no peito e outra na barriga. Respire de forma que apenas a barriga suba. Pratique por 5 minutos","tip":"A maioria de nós respira de forma superficial. Esta técnica reconecta com a respiração natural"},
    {"day":2,"title":"Respiração 4-7-8","description":"Técnica do Dr. Andrew Weil para reduzir ansiedade rapidamente","activity":"Inspire por 4 tempos, segure por 7, expire por 8. Repita 4 vezes","tip":"Esta técnica ativa o sistema nervoso parassimpático — seu freio natural"},
    {"day":3,"title":"Respiração Quadrada","description":"Quatro lados iguais para equilibrar sistema nervoso","activity":"Inspire por 4, segure por 4, expire por 4, segure por 4. Repita por 5 minutos","tip":"Usada por forças especiais e atletas de alto rendimento"},
    {"day":4,"title":"Respiração Alternada","description":"Técnica do yoga (Nadi Shodhana) para equilíbrio","activity":"Feche a narina direita, inspire pela esquerda. Feche a esquerda, expire pela direita. Alterne por 5 minutos","tip":"Equilibra os hemisférios cerebrais e acalma pensamentos agitados"},
    {"day":5,"title":"Respiração Coerente","description":"5 respirações por minuto para máxima coerência cardíaca","activity":"Inspire por 6 segundos, expire por 6 segundos. Mantenha por 10 minutos","tip":"Esta frequência cria coerência entre coração, mente e emoções"},
    {"day":6,"title":"Respiração para Dormir","description":"Acalme o sistema nervoso antes de dormir","activity":"Deite-se. Respire lentamente, fazendo a expiração duas vezes mais longa que a inspiração. Continue por 10 minutos","tip":"Expiração longa ativa o nervo vago e induz relaxamento profundo"},
    {"day":7,"title":"Respiração de Emergência","description":"Para momentos de ansiedade intensa ou pânico","activity":"Inspire FUNDO, expire DEVAGAR e longo. Repita até sentir o coração desacelerar","tip":"Esta é sua âncora. Guarde no bolso para momentos difíceis"}
  ]'::jsonb
)
ON CONFLICT (slug) DO NOTHING;

