INSERT INTO guided_prompts (text, theme, day_of_week, plan_level) VALUES
-- Domingo (0)
('Como estou chegando nessa semana? O que carrego do que ficou para trás?', 'reflexão', 0, 'free'),
('Se eu pudesse descansar de verdade hoje, o que isso pareceria?', 'descanso', 0, 'free'),
('Que pensamento ou sentimento ficou preso em mim essa semana?', 'emoções', 0, 'essential'),
-- Segunda (1)
('O que eu quero intencionalmente para essa semana?', 'intenção', 1, 'free'),
('Qual é o menor passo que eu posso dar hoje?', 'ação', 1, 'free'),
('O que meu corpo está pedindo hoje?', 'corpo', 1, 'essential'),
('Que história sobre mim mesmo eu carrego e preciso revisar?', 'identidade', 1, 'therapeutic'),
-- Terça (2)
('O que me dá energia? Quando foi a última vez que fiz isso?', 'energia', 2, 'free'),
('Algo que ainda não disse para alguém, mas que eu precisaria dizer.', 'comunicação', 2, 'essential'),
('Qual limite eu preciso colocar (ou reafirmar) esta semana?', 'limites', 2, 'essential'),
-- Quarta (3)
('No meio da semana: o que está indo bem? O que eu preciso soltar?', 'pausa', 3, 'free'),
('Como eu me trato quando erro? É com a mesma gentileza que eu trataria um amigo?', 'autocompaixão', 3, 'free'),
('O que minha dor (física ou emocional) está tentando me dizer?', 'dor', 3, 'therapeutic'),
-- Quinta (4)
('O que eu aprendi sobre mim mesmo essa semana?', 'autoconhecimento', 4, 'free'),
('Que emoção eu venho evitando? O que ela precisa de mim?', 'emoções', 4, 'essential'),
('Se eu me permitisse ser vulnerável, o que eu diria?', 'vulnerabilidade', 4, 'therapeutic'),
-- Sexta (5)
('O que eu quero celebrar desta semana, mesmo que pequeno?', 'gratidão', 5, 'free'),
('Algo que aconteceu esta semana que eu não esperava e que foi bom.', 'surpresa', 5, 'free'),
('Como meu relacionamento comigo mesmo tem estado?', 'autorelacionamento', 5, 'essential'),
-- Sábado (6)
('O que eu faria diferente se soubesse que não poderia errar?', 'coragem', 6, 'free'),
('Escreva uma coisa que você ama em si mesmo, sem condições.', 'amor-próprio', 6, 'free'),
('O que propósito significa para mim nesse momento da vida?', 'propósito', 6, 'therapeutic'),
-- Prompts without specific day
('Um pequeno orgulho do dia foi…', 'conquista', NULL, 'essential'),
('Hoje, algo que ajudou minha dor foi…', 'dor', NULL, 'essential'),
('Me senti compreendido quando…', 'conexão', NULL, 'essential'),
('Um pensamento que se repete em mim é…', 'pensamentos', NULL, 'essential'),
('Quando sinto ansiedade, o que geralmente acontece antes é…', 'ansiedade', NULL, 'essential'),
('Algo que eu preciso perdoar em mim mesmo é…', 'perdão', NULL, 'therapeutic'),
('O que meu corpo me pediu hoje que eu não ouvi?', 'corpo', NULL, 'therapeutic'),
('Em que momento eu me senti mais eu mesmo esta semana?', 'autenticidade', NULL, 'therapeutic')
ON CONFLICT DO NOTHING;
